mapper.select:
SELECT user_id, following_count, follower_count, updated_at
FROM user_follow_stats
WHERE user_id = #{userId}

mapper.update:
UPDATE user_follow_stats
SET following_count = IF(following_count > 0, following_count - 1, 0)
WHERE user_id = #{userId}

UPDATE user_follow_stats
SET follower_count = IF(follower_count > 0, follower_count - 1, 0)
WHERE user_id = #{userId}
